import { Instructor, OpenAI } from 'instructor';
import { z } from 'zod';

const client = new Instructor({
  client: new OpenAI({ apiKey: process.env.OPENAI_API_KEY }),
});

const InvoiceSchema = z.object({
  invoiceNumber: z.string().describe('Unique invoice ID'),
  totalAmount: z.number(),
  date: z.string(),
  customer: z.string(),
});

type Invoice = z.infer<typeof InvoiceSchema>;

const invoice = await client.chat.completions.create({
  model: 'gpt-4o-mini',
  schema: InvoiceSchema,
  messages: [{
    role: 'user',
    content: 'Extract invoice: #INV-5678 on 2024-10-02 for Beta Inc $1,800',
  }],
}) as Invoice;

console.log(JSON.stringify(invoice, null, 2));

