import { Instructor, OpenAI } from 'instructor';
import { z } from 'zod';
import { verify, Verifier } from 'vex-sdk';

const client = new Instructor({
  client: new OpenAI(),
});

const DocumentType = z.enum(['invoice', 'receipt', 'contract']);

const DocSchema = z.object({
  docType: DocumentType,
  amount: z.number().positive(),
  vendor: z.string(),
});

const verifier = new Verifier({
  checks: ['schema_compliance', 'field_accuracy', 'type_consistency'],
});

const extractDocument = verify(
  async (text: string) => {
    return await client.chat.completions.create({
      model: 'gpt-4o-mini',
      schema: DocSchema,
      messages: [{ role: 'user', content: text }],
    }) as z.infer<typeof DocSchema>;
  },
  { verifier }
);

const doc = await extractDocument('Invoice from VendorY $2200');
console.log(JSON.stringify(doc, null, 2));
